schemas:
DEFINE TABLE OVERWRITE _input_article_mentions_ SCHEMAFULL TYPE RELATION IN _input_articles_;

DEFINE FIELD OVERWRITE weight ON TABLE _input_article_mentions_ TYPE float;

# DEFINE FIELD OVERWRITE field ON _input_article_mentions_;
DEFINE TABLE OVERWRITE _input_articles_ SCHEMAFULL;

DEFINE FIELD OVERWRITE text ON _input_articles_ TYPE string;
DEFINE FIELD OVERWRITE embeddings ON TABLE _input_articles_ TYPE array<float> ASSERT array::len($value) = 1024;

DEFINE INDEX OVERWRITE embeddings_vector_index ON _input_articles_
    FIELDS embeddings
    MTREE DIMENSION 1024
    DIST COSINE;
DEFINE TABLE OVERWRITE _table_disambiguations_ SCHEMAFULL;

DEFINE FIELD OVERWRITE id ON _table_disambiguations_ TYPE string;
DEFINE FIELD OVERWRITE embeddings ON _table_disambiguations_ TYPE array<float> ASSERT array::len($value) = 1024;

DEFINE INDEX OVERWRITE embeddings_vector_index ON _table_disambiguations_
    FIELDS embeddings
    MTREE DIMENSION 1024
    DIST COSINE;
DEFINE TABLE OVERWRITE script_migration SCHEMAFULL
    PERMISSIONS
        FOR select FULL
        FOR create, update, delete NONE;

DEFINE FIELD OVERWRITE script_name ON script_migration TYPE string;
DEFINE FIELD OVERWRITE executed_at ON script_migration TYPE datetime VALUE time::now() READONLY;
